/* 결정적 픽 (회기 인덱스로 안정적 선택) - 새로고침에도 같은 결과 */
const pickStable = (arr, seed) => {
  if (!arr || arr.length === 0) return '';
  const idx = Math.abs(Number(seed) || 0) % arr.length;
  return arr[idx];
};

/* 문자열 → 정수 해시 (다양성 확보용 seed 변이)
   같은 점수 패턴이라도 아동별로 다른 표현이 선택되도록, 아동 이름 등을 seed에 섞는다.
   결정적이라 같은 아동·같은 회기에서는 항상 같은 결과 (새로고침 후에도 동일). */
const strHash = (s) => {
  if (!s) return 0;
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0; // 32-bit
  }
  return Math.abs(h);
};

const calcAverage = (sessions) => {
  const valid = sessions.filter((s) => s != null && s !== '' && !isNaN(Number(s)));
  if (valid.length === 0) return null;
  const sum = valid.reduce((a, b) => a + Number(b), 0);
  return sum / valid.length;
};

const formatAvg = (avg) => (avg == null ? '-' : avg.toFixed(1));

/* ────────────────────────────────────────────────
   한국어 받침 판별 및 조사 자동 보정
   ────────────────────────────────────────────────
   한글 유니코드 한 글자의 받침 인덱스:
     (코드 - 0xAC00) % 28
     0 = 받침 없음, 1~27 = 받침 있음
   영어/숫자/기호로 끝나면 받침 있음으로 보수적 처리 (한국어 환경 기본).
   ──────────────────────────────────────────────── */
const hasJongseong = (word) => {
  if (!word) return false;
  const lastChar = String(word).trim().slice(-1);
  const code = lastChar.charCodeAt(0);
  /* 한글 음절 범위 (가 ~ 힣) */
  if (code >= 0xAC00 && code <= 0xD7A3) {
    return (code - 0xAC00) % 28 !== 0;
  }
  /* 한글이 아니면 발음 기반 대응이 필요하지만, 보수적으로 받침 있음 처리 */
  return true;
};

/* 받침 유무에 따라 변하는 조사 쌍 (받침 있음 → 받침 없음) */
const PARTICLE_PAIRS = {
  '이': '가',     '가': '가',
  '은': '는',     '는': '는',
  '을': '를',     '를': '를',
  '과': '와',     '와': '와',
  '이라는': '라는','라는': '라는',
  '이라고': '라고','라고': '라고',
  '이라': '라',   '라': '라',
  '으로': '로',   '로': '로',
  '으로서': '로서','로서': '로서',
  '으로써': '로써','로써': '로써',
  '이며': '며',   '며': '며',
  '이나': '나',   '나': '나',
  '이라도': '라도','라도': '라도',
  '이든': '든',   '든': '든',
  '이라서': '라서','라서': '라서',
};

/* 받침 무관 (그대로) 조사 목록 */
const NEUTRAL_PARTICLES = ['의', '에', '에게', '에서', '에서도', '도', '만', '께', '께서', '한테', '한테서', '보다', '처럼', '같이', '마저', '조차', '부터', '까지', '뿐', '밖에', '대로', '쯤'];

/* 단어 + 조사 → 받침에 맞는 올바른 조사 적용 */
const fixParticle = (word, particle) => {
  if (!word || !particle) return word + (particle || '');
  const hasJong = hasJongseong(word);

  /* 받침 무관 조사는 그대로 */
  if (NEUTRAL_PARTICLES.includes(particle)) {
    return word + particle;
  }

  /* 받침 변화 조사 처리 */
  if (PARTICLE_PAIRS[particle]) {
    /* 받침 없는 형태 → 받침 있는 형태 역매핑 */
    const reverseMap = {
      '가': '이', '는': '은', '를': '을', '와': '과',
      '라는': '이라는', '라고': '이라고', '라': '이라',
      '로': '으로', '로서': '으로서', '로써': '으로써',
      '며': '이며', '나': '이나', '라도': '이라도', '든': '이든', '라서': '이라서',
    };
    const withJong = reverseMap[particle] || particle;   /* 받침 있는 형태 */
    const withoutJong = PARTICLE_PAIRS[particle];        /* 받침 없는 형태 */
    return word + (hasJong ? withJong : withoutJong);
  }

  /* 기타 조사는 그대로 */
  return word + particle;
};

/* ────────────────────────────────────────────────
   보고서 텍스트에서 "아동" 일반 용어를 아동 이름으로 치환 + 조사 자동 보정
   ────────────────────────────────────────────────
   - 원본 데이터는 "아동" + 받침 있는 단어용 조사로 작성됨
   - 받침 없는 이름(예: 지수)이면 조사도 자동으로 변환 (아동이 → 지수가)
   - 보호자 안내문·중간보고서·종결보고서의 본문 표시 시점에 적용
   - "아동 관리", "아동 등록" 같은 시스템 용어는 영향 없음 (다른 곳에 하드코딩됨)
   - 합성어 화이트리스트(아동기, 아동심리, 아동학)는 자리표시자로 잠시 빼두고
     치환 완료 후 복원하여 보존
   ──────────────────────────────────────────────── */
const CHILD_COMPOUND_WORDS = ['아동기', '아동심리', '아동학', '아동복지', '아동발달', '아동보호'];

const replaceChildPronoun = (text, childOrName) => {
  if (!text || !childOrName) return text || '';
  /* 두 번째 인자: 문자열(이름) 또는 객체({name, nickname}) 둘 다 허용
     - 문자열: 그 이름을 그대로 사용
     - 객체: nickname이 있으면 우선, 없으면 name 사용 */
  let name;
  if (typeof childOrName === 'string') {
    name = childOrName.trim();
  } else if (typeof childOrName === 'object') {
    name = (childOrName.nickname || childOrName.name || '').trim();
  } else {
    return text;
  }
  if (!name) return text;

  /* 호칭형 변환: 받침 있는 이름엔 '이'를 붙여 자연스러운 구어체로
     (다솔 → 다솔이 → 다솔이는/다솔이가/다솔이를). 받침 없으면 그대로(지우 → 지우는).
     '이'가 붙으면 받침이 없어지므로 이후 조사는 자동으로 받침없음 형태가 됨. */
  const callName = hasJongseong(name) ? name + '이' : name;

  /* 1단계: 합성어를 자리표시자로 임시 치환 (보존용) */
  const placeholders = {};
  let result = String(text);
  CHILD_COMPOUND_WORDS.forEach((compound, idx) => {
    const placeholder = `\u0000CMPD${idx}\u0000`;
    placeholders[placeholder] = compound;
    result = result.split(compound).join(placeholder);
  });

  /* 2단계: "아동" + 받침 변화 조사 → 호칭형 이름 + 올바른 조사
     긴 조사부터 매칭 (이라는 < 이라 < 이) */
  const variableParticles = [
    '이라는', '이라고', '이라서', '이라도',
    '으로서', '으로써', '으로',
    '이며', '이나', '이든',
    '이', '가', '은', '는', '을', '를', '과', '와',
  ];

  for (const particle of variableParticles) {
    const pattern = new RegExp(`아동${particle}`, 'g');
    result = result.replace(pattern, fixParticle(callName, particle));
  }

  /* 3단계: "아동" + 받침 무관 조사 → 호칭형 이름 + 같은 조사 */
  for (const particle of NEUTRAL_PARTICLES) {
    const pattern = new RegExp(`아동${particle}`, 'g');
    result = result.replace(pattern, callName + particle);
  }

  /* 4단계: 단독으로 남아있는 "아동" → 호칭형 이름 */
  result = result.replace(/아동/g, callName);

  /* 5단계: 자리표시자를 합성어로 복원 */
  Object.entries(placeholders).forEach(([ph, compound]) => {
    result = result.split(ph).join(compound);
  });

  return result;
};

const todayStr = () => {
  const d = new Date();
  return `${d.getFullYear()}년 ${d.getMonth() + 1}월 ${d.getDate()}일`;
};

/* "오늘"을 YYYY-MM-DD 로컬 날짜 (KST 기준)로 반환 — toISOString의 UTC 변환 회피 */
const todayISO = () => {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const uid = () => `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

/* ────────────────────────────────────────────────
   이름 → 호칭(별명) 자동 추출
   ────────────────────────────────────────────────
   한국 이름에서 보고서/안내문용 친근한 호칭 자동 생성:
   - 3글자 이름 (가장 흔함): 첫 글자(성) 제거 → "주하민" → "하민"
   - 4글자 이름 (대부분 복성 1글자 성+3글자 이름 또는 복성 2+2): 뒤 2글자 → "황보경수" → "경수"
   - 2글자 이름 (외자 이름): 그대로 사용 (성 빼면 1글자 어색)
   - 1글자 이름: 그대로 사용
   복성(황보, 남궁, 선우, 독고, 제갈, 서문, 사공, 동방) 4글자는 뒤 2글자 추출
   치료사가 등록 폼에서 직접 수정 가능하므로 정확하지 않아도 OK
   ──────────────────────────────────────────────── */
const COMPOUND_SURNAMES = ['황보', '남궁', '선우', '독고', '제갈', '서문', '사공', '동방'];

const extractNickname = (fullName) => {
  if (!fullName) return '';
  const name = String(fullName).trim();
  if (name.length <= 2) return name;  // 2글자 이하는 그대로

  /* 4글자: 복성 여부 확인 */
  if (name.length === 4) {
    const possibleCompound = name.slice(0, 2);
    if (COMPOUND_SURNAMES.includes(possibleCompound)) {
      return name.slice(2);  // 복성 제거 → 뒤 2글자
    }
    /* 일반 4글자 이름 (1글자 성 + 3글자 이름)도 뒤 2글자 추출이 친근함 */
    return name.slice(2);
  }

  /* 3글자 표준 한국 이름: 첫 글자(성) 제거 */
  if (name.length === 3) {
    /* 혹시라도 복성 1글자 + 외자 이름(예: "남궁이") 가능성은 매우 드물어 무시 */
    return name.slice(1);
  }

  /* 5글자 이상: 뒤 2~3글자 추출 */
  return name.slice(-2);
};

/* ────────────────────────────────────────────────
   회기 일정 계산 (시작일 + 요일 + 건너뛴 회기)
   ────────────────────────────────────────────────
   주 1회 고정, 같은 요일 매주 진행이 기본.
   휴일/결석으로 빠진 회기는 두 가지 방식으로 처리:
   - postponed: 다음 주로 일정 밀림 (회기 번호 유지, 날짜만 이동)
   - lost: 그 회기 영구 결손 (다음 주는 다음 회기 번호)
   특정 회기의 날짜를 직접 지정한 경우(manualOverrides)는 그 값을 우선 사용.
   ──────────────────────────────────────────────── */
const WEEKDAY_LABELS = ['일', '월', '화', '수', '목', '금', '토'];

const calculateSessionDates = (startDate, weekday, plannedSessions, skippedSessions, manualOverrides) => {
  if (!startDate) return [];

  const start = new Date(startDate + 'T00:00:00');
  if (isNaN(start.getTime())) return [];

  /* 로컬 날짜를 YYYY-MM-DD로 추출 — toISOString()의 UTC 변환 문제 회피
     (한국은 UTC+9라 자정 직후엔 toISOString().slice(0,10)이 어제로 떨어짐) */
  const toLocalISO = (date) => {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, '0');
    const d = String(date.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  };

  /* 시작일을 첫 회기 요일에 맞춰 보정 */
  const startWeekday = start.getDay();
  const targetWeekday = weekday != null ? Number(weekday) : startWeekday;
  let firstSession = new Date(start);
  if (startWeekday !== targetWeekday) {
    const diff = (targetWeekday - startWeekday + 7) % 7;
    firstSession.setDate(firstSession.getDate() + diff);
  }

  const skipped = skippedSessions || [];
  const overrides = manualOverrides || {};

  /* 건너뛴 회기 맵: { sessionNo: 'postponed' | 'lost' } */
  const skipMap = {};
  skipped.forEach((s) => { skipMap[s.sessionNo] = s.type; });

  const dates = [];
  let cursor = new Date(firstSession);
  let sessionNo = 1;
  const handledSkips = new Set();  // 이미 처리한 skip 회기

  /* 안전 장치: 최대 1000주까지만 계산 */
  let safety = 0;
  while (sessionNo <= plannedSessions && safety < 1000) {
    safety++;
    const dateStr = toLocalISO(cursor);
    const skipType = skipMap[sessionNo];

    /* 1. 수동 지정 우선 */
    if (overrides[sessionNo]) {
      dates.push({
        sessionNo,
        date: overrides[sessionNo],
        weekday: WEEKDAY_LABELS[new Date(overrides[sessionNo] + 'T00:00:00').getDay()],
        type: 'manual',
        original: dateStr,
      });
      sessionNo++;
      cursor.setDate(cursor.getDate() + 7);
      continue;
    }

    /* 2. lost: 회기 영구 결손, 같은 주에 다음 회기가 들어옴 */
    if (skipType === 'lost' && !handledSkips.has(sessionNo)) {
      dates.push({
        sessionNo,
        date: null,
        weekday: WEEKDAY_LABELS[cursor.getDay()],
        type: 'lost',
        original: dateStr,
      });
      handledSkips.add(sessionNo);
      sessionNo++;
      continue;  // cursor 그대로
    }

    /* 3. postponed: 그 주는 회기 없음, 같은 회기 번호가 다음 주로 이동 */
    if (skipType === 'postponed' && !handledSkips.has(sessionNo)) {
      dates.push({
        sessionNo,
        date: null,
        weekday: WEEKDAY_LABELS[cursor.getDay()],
        type: 'postponed',
        original: dateStr,
      });
      handledSkips.add(sessionNo);
      cursor.setDate(cursor.getDate() + 7);
      continue;  // sessionNo 그대로
    }

    /* 4. 일반 회기 */
    dates.push({
      sessionNo,
      date: dateStr,
      weekday: WEEKDAY_LABELS[cursor.getDay()],
      type: 'normal',
    });
    sessionNo++;
    cursor.setDate(cursor.getDate() + 7);
  }

  return dates;
};

/* ────────────────────────────────────────────────
   월 단위 회기 묶음 계산
   ────────────────────────────────────────────────
   "한 달 = 한 묶음" 규칙: 시작 회기(startNo)의 날짜가 속한 '월'에 들어가는
   모든 회기 번호를 반환한다. 그 달에 5주가 있으면 5회기, 4주면 4회기.
   - schedule: calculateSessionDates() 결과 ([{ sessionNo, date }, ...])
   - 날짜가 없는 회기(lost/postponed 등)는 직전 정상 회기의 달을 따른다.
   - 최소 1개, 안전상 최대 6개로 제한. 일정이 없으면 기존 방식대로 4개 고정. */
const getMonthlyBundle = (startNo, schedule) => {
  const FALLBACK = [startNo, startNo + 1, startNo + 2, startNo + 3];
  if (!Array.isArray(schedule) || schedule.length === 0) return FALLBACK;

  const byNo = {};
  schedule.forEach((s) => { byNo[s.sessionNo] = s; });

  /* 시작 회기의 '월' 결정 (날짜 없으면 인접 회기에서 보완) */
  const monthOf = (no) => {
    const s = byNo[no];
    if (s && s.date) return s.date.slice(0, 7); // YYYY-MM
    return null;
  };
  let baseMonth = monthOf(startNo);
  if (!baseMonth) {
    /* 시작 회기 날짜가 없으면 이후 가장 가까운 정상 회기의 달 사용 */
    for (let n = startNo + 1; n <= startNo + 6; n++) {
      const m = monthOf(n);
      if (m) { baseMonth = m; break; }
    }
  }
  if (!baseMonth) return FALLBACK;

  const bundle = [];
  let n = startNo;
  let lastMonth = baseMonth;
  while (n <= startNo + 6) {
    const s = byNo[n];
    if (!s) break;                       // 일정에 더 이상 회기 없음
    const m = s.date ? s.date.slice(0, 7) : lastMonth;  // 날짜 없으면 직전 달 승계
    if (m !== baseMonth) break;          // 다음 달로 넘어가면 묶음 종료
    bundle.push(n);
    lastMonth = m;
    n++;
  }
  return bundle.length > 0 ? bundle : FALLBACK;
};

