/* ────────────────────────────────────────────────
   반(班)별 문장 풀 선택 헬퍼
   빌더에 전달된 domains 배열이 심화반(EVAL_DOMAINS_ADVANCED)이면 _ADVANCED 풀을,
   아니면 기초반 풀을 반환한다. (getDomains/getCurriculum/getParentGuides와 동일 패턴)
   콜러가 getDomains(child)를 넘기므로 심화반일 때 참조 동일성(===)이 성립한다.
   미지정/알수없음 → 기초반 폴백. ──────────────────────────────────────────────── */
const isAdvancedDomains = (domains) => domains === EVAL_DOMAINS_ADVANCED;
const poolDescriptions = (domains) =>
  isAdvancedDomains(domains) ? CLINICAL_DESCRIPTIONS_ADVANCED : CLINICAL_DESCRIPTIONS;
const poolNextProcedures = (domains) =>
  isAdvancedDomains(domains) ? CLINICAL_NEXT_PROCEDURES_ADVANCED : CLINICAL_NEXT_PROCEDURES;
const poolHomeGuidance = (domains) =>
  isAdvancedDomains(domains) ? CLINICAL_HOME_GUIDANCE_ADVANCED : CLINICAL_HOME_GUIDANCE;
const poolDomainStrengths = (domains) =>
  isAdvancedDomains(domains) ? DOMAIN_STRENGTHS_ADVANCED : DOMAIN_STRENGTHS;
const poolDomainRecommendations = (domains) =>
  isAdvancedDomains(domains) ? DOMAIN_RECOMMENDATIONS_ADVANCED : DOMAIN_RECOMMENDATIONS;
const poolTransitionByDomain = (domains) =>
  isAdvancedDomains(domains) ? TRANSITION_BY_DOMAIN_ADVANCED : TRANSITION_BY_DOMAIN;
const poolTransitionSchoolNotice = (domains) =>
  isAdvancedDomains(domains) ? TRANSITION_SCHOOL_NOTICE_ADVANCED : TRANSITION_SCHOOL_NOTICE;
const poolIepNextGoals = (domains) =>
  isAdvancedDomains(domains) ? IEP_NEXT_GOALS_ADVANCED : IEP_NEXT_GOALS;

/* 자동 생성 - 다음 기간 IEP-Style 목표 추출
   scores : { domainKey: averageScore } 형태
   periodLabel : '다음 회기' / '다음 8주' / '다음 단계 프로그램 (3~6개월)' 등
   childName : 호칭 또는 이름 (목표문에 주체로 삽입) */
const buildNextGoals = (scores, periodLabel, childName, domains = EVAL_DOMAINS) => {
  const nameHash = strHash(childName);
  const targetName = childName || '아동';

  const goals = [];
  domains.forEach((dom) => {
    const s = scores?.[dom.key];
    if (s == null || isNaN(Number(s))) return;
    const score = Number(s);
    let band;
    if (score >= 3.5) band = 'high';
    else if (score >= 2.5) band = 'mid';
    else band = 'low';

    const pool = poolIepNextGoals(domains)[dom.key]?.[band];
    if (!pool || pool.length === 0) return;

    /* 영역별 다양성 — 같은 점수 패턴이어도 아동마다 다른 목표 선택 */
    const seed = nameHash + (dom.key?.length || 0) + Math.floor(score * 10);
    const goal = pickStable(pool, seed);
    goals.push({ dom, score, band, goal });
  });

  if (goals.length === 0) return '';

  /* 우선순위 정렬: low(도전 영역) → mid(형성 중) → high(유지·일반화) */
  const order = { low: 0, mid: 1, high: 2 };
  goals.sort((a, b) => order[a.band] - order[b.band]);

  const lines = [];
  lines.push(`${periodLabel} 권장 목표 (IEP-Style)`);
  lines.push(`측정 가능한 행동 + 조건 + 기준 형식으로 정리한 다음 기간 목표이며, 회기 중 데이터로 진행도를 점검할 수 있습니다.`);
  lines.push('');
  /* 본문에는 periodLabel 반복 안 함 — 헤더에 이미 명시됨.
     8개 영역마다 "다음 단계 프로그램(3~6개월) 동안" 반복되면 단조롭고 길어짐 */
  goals.forEach(({ dom, goal }) => {
    lines.push(`[${dom.label}] 아동은 ${goal}.`);
  });

  return replaceChildPronoun(lines.join('\n'), childName);
};

