const abaLevelToStatement = (domainKey, score) => {
  const stmts = ABA_DOMAIN_STATEMENTS[domainKey];
  if (!stmts) return '';
  const s = Number(score);
  if (isNaN(s)) return '';
  if (s >= 3.5) return stmts.high;
  if (s >= 2.5) return stmts.mid;
  return stmts.low;
};

/* 변화량 → ABA 표현 (수치 기반, 감성 표현 배제) */
const changeToAbaPhrase = (diff) => {
  if (diff == null) return null;
  if (diff >= 1.0) return { tag: '현저한 향상', detail: `평균 점수 +${diff.toFixed(1)} 상승`, key: 'major' };
  if (diff >= 0.5) return { tag: '유의한 향상', detail: `평균 점수 +${diff.toFixed(1)} 상승`, key: 'meaningful' };
  if (diff >= 0.2) return { tag: '소폭 향상', detail: `평균 점수 +${diff.toFixed(1)} 상승`, key: 'small' };
  if (diff > -0.2) return { tag: '수행 수준 유지', detail: '평균 점수 변동 0.2점 미만', key: 'stable' };
  return { tag: '수행 변동', detail: `평균 점수 ${diff.toFixed(1)} 하락`, key: 'declining' };
};

/* 중간보고서 - 분기 총평 자동 생성 (ABA 임상 표현) */
/* 임상 진술 어미를 현재형(~합니다)으로 변환 - 영역별 현재 수준 진술용 */
const toPresentTense = (text) => {
  if (!text) return text;
  return text
    .replace(/관찰되었습니다/g, '관찰됩니다')
    .replace(/관찰되었다/g, '관찰됩니다')
    .replace(/확인되었습니다/g, '확인됩니다')
    .replace(/확인되었다/g, '확인됩니다')
    .replace(/수행하였습니다/g, '수행합니다')
    .replace(/수행하였다/g, '수행합니다')
    .replace(/필요하였습니다/g, '필요합니다')
    .replace(/필요하였다/g, '필요합니다')
    .replace(/요구되었습니다/g, '요구됩니다')
    .replace(/요구되었다/g, '요구됩니다')
    .replace(/가능하였습니다/g, '가능합니다')
    .replace(/가능하였다/g, '가능합니다')
    .replace(/보였습니다/g, '보입니다')
    .replace(/보였다/g, '보입니다')
    .replace(/참여하였습니다/g, '참여합니다')
    .replace(/참여하였다/g, '참여합니다')
    .replace(/모방하였습니다/g, '모방합니다')
    .replace(/모방하였다/g, '모방합니다')
    .replace(/완료하였습니다/g, '완료합니다')
    .replace(/완료하였다/g, '완료합니다')
    .replace(/적용하였습니다/g, '적용합니다')
    .replace(/적용하였다/g, '적용합니다')
    .replace(/단축되었습니다/g, '단축되는 양상입니다')
    .replace(/단축되었다/g, '단축되는 양상입니다')
    .replace(/정착되었습니다/g, '정착된 상태입니다')
    .replace(/정착되었다/g, '정착된 상태입니다')
    .replace(/시도하였습니다/g, '시도합니다')
    .replace(/시도하였다/g, '시도합니다')
    .replace(/관찰되지 않았습니다/g, '관찰되지 않습니다')
    .replace(/확인되지 않았습니다/g, '확인되지 않습니다')
    .replace(/되지 않았습니다/g, '되지 않습니다')
    .replace(/않았습니다/g, '않습니다')
    .replace(/않았다/g, '않습니다')
    .replace(/이었다/g, '입니다');
};

const buildMidQuarterComment = (monthlyData, childName, domains = EVAL_DOMAINS) => {
  /* monthlyData: { months: [...], data: { domainKey: { 'YYYY-MM': value } } }
     구 구조 { domainKey: { jan, feb, mar } }도 자동 변환 처리 */
  /* 표현 다양성: 아동 이름 해시를 seed에 섞어 동일 점수 패턴에서도 아동별 다른 문장 선택 */
  const nameHash = strHash(childName);

  let months, dataMap;
  if (monthlyData?.months && monthlyData?.data) {
    months = monthlyData.months;
    dataMap = monthlyData.data;
  } else {
    /* 구 구조 호환 */
    months = ['jan', 'feb', 'mar'];
    dataMap = monthlyData || {};
  }

  const results = [];
  domains.forEach((dom) => {
    const valsRaw = months.map((m) => dataMap[dom.key]?.[m]);
    const vals = valsRaw
      .map((v) => (v != null && v !== '' ? Number(v) : null))
      .filter((v) => v != null && !isNaN(v));
    if (vals.length === 0) return;
    const first = vals[0];
    const last = vals[vals.length - 1];
    const avg = vals.reduce((a, b) => a + b, 0) / vals.length;
    const diff = vals.length >= 2 ? (last - first) : 0;
    results.push({ dom, first, last, avg, diff, vals });
  });

  if (results.length === 0) return '';

  /* 월 형식 여부 판정 (intro 문구 분기에 사용) */
  const isMonthFormat = months.length > 0 && months[0].length === 7 && months[0].includes('-');

  const lines = [];

  /* 변화 분류 */
  const changes = results
    .map((r) => ({ ...r, phrase: changeToAbaPhrase(r.diff) }))
    .filter((r) => r.phrase);
  const major = changes.filter((c) => c.phrase.key === 'major');
  const meaningful = changes.filter((c) => c.phrase.key === 'meaningful');
  const small = changes.filter((c) => c.phrase.key === 'small');
  const stable = changes.filter((c) => c.phrase.key === 'stable');
  const declining = changes.filter((c) => c.phrase.key === 'declining');

  const lowDomains = results.filter((r) => r.avg < 2.5);
  const midDomains = results.filter((r) => r.avg >= 2.5 && r.avg < 3.5);
  /* highDomains는 last도 함께 봐서 평균만 높고 현재는 낮은 케이스 배제
     (예: 5→4→2 평균 3.67이지만 현재는 2점 → "안정적 수행"이라 부르면 어색) */
  const highDomains = results.filter((r) => r.avg >= 3.5 && r.last >= 3.5);

  /* 1. 전반 요약 (한 단락 자연스러운 흐름) */
  const overallParts = [];
  const usedKeys = new Set();
  if (highDomains.length > 0) {
    /* 6개 이상이면 "전반 영역" 표현, 적으면 영역명 나열 */
    if (highDomains.length >= 6) {
      overallParts.push(`전반 영역에서 안정적인 수행을 보이고 있습니다`);
      highDomains.forEach((d) => usedKeys.add(d.dom.key));
    } else {
      const names = highDomains.slice(0, 3).map((d) => { usedKeys.add(d.dom.key); return d.dom.label; }).join(', ');
      overallParts.push(`${names} 영역에서 안정적인 수행을 보이고 있습니다`);
    }
  }
  if (major.length > 0 || meaningful.length > 0) {
    /* 안정적 수행에 이미 언급된 영역은 중복 표시 제외 */
    const growthAll = [...major, ...meaningful].filter((c) => !usedKeys.has(c.dom.key));
    if (growthAll.length > 0) {
      /* 성장 영역이 많을 때(6개 이상)는 "전반 영역" 표현, 적으면 영역명 나열 */
      if (growthAll.length >= 6) {
        overallParts.push(`전반 영역에서 의미 있는 성장이 관찰되었습니다`);
        growthAll.forEach((c) => usedKeys.add(c.dom.key));
      } else {
        const names = growthAll.slice(0, 3).map((c) => { usedKeys.add(c.dom.key); return c.dom.label; }).join(', ');
        overallParts.push(`${names} 영역은 기간 내 의미 있는 성장이 관찰되었습니다`);
      }
    }
  }
  /* midDomains 첫 줄 - declining 다수면 "수행 변동", stable 다수면 "중간 수준 안정", 그 외 "점진적 향상" */
  if (overallParts.length === 0 && midDomains.length > 0) {
    const midKeySet = new Set(midDomains.map((d) => d.dom.key));
    const stableMidCount = stable.filter((s) => midKeySet.has(s.dom.key)).length;
    const decliningMidCount = declining.filter((s) => midKeySet.has(s.dom.key)).length;
    /* 6개 이상이면 "전반 영역" 표현 */
    const labelStr = midDomains.length >= 6
      ? '전반 영역'
      : `${midDomains.slice(0, 2).map((d) => d.dom.label).join(', ')} 영역`;

    if (decliningMidCount > stableMidCount && decliningMidCount >= midDomains.length / 2) {
      /* 하락 영역이 다수면 "수행 변동" — 5→3→1 같은 케이스 */
      overallParts.push(`${labelStr}에서 수행 변동이 관찰되어 점검이 필요한 시점입니다`);
    } else if (stableMidCount >= midDomains.length / 2) {
      /* stable이 다수면 "중간 수준 안정" — 3→3→3 같은 케이스 */
      overallParts.push(`${labelStr}에서 중간 수준의 수행이 안정적으로 관찰되고 있습니다`);
    } else {
      /* 그 외 일반 mid 흐름 */
      overallParts.push(`${labelStr}에서 점진적인 향상을 보이고 있습니다`);
    }
  }
  /* declining만 있는 경우 (모든 영역 하락) 도입 누락 방지 */
  if (overallParts.length === 0 && declining.length > 0) {
    if (declining.length >= 6) {
      overallParts.push(`전반 영역에서 수행 변동이 관찰되어 지속적인 점검이 필요한 시점입니다`);
    } else {
      const names = declining.slice(0, 3).map((d) => d.dom.label).join(', ');
      overallParts.push(`${names} 영역에서 수행 변동이 관찰되어 지속적인 점검이 필요한 시점입니다`);
    }
  }
  /* lowDomains만 있고 stable한 경우 (모든 영역 낮은 점수로 정체) 도입 누락 방지 */
  if (overallParts.length === 0 && lowDomains.length > 0) {
    if (lowDomains.length >= 6) {
      overallParts.push(`전반 영역에서 지속적인 지원이 필요한 시점이며, 단계적 접근을 이어갈 예정입니다`);
    } else {
      const names = lowDomains.slice(0, 3).map((d) => d.dom.label).join(', ');
      overallParts.push(`${names} 영역에서 지속적인 지원이 필요한 시점이며, 단계적 접근을 이어갈 예정입니다`);
    }
  }
  if (overallParts.length > 0) {
    const intro = isMonthFormat
      ? `지난 ${months.length}개월 동안`
      : months.length >= 2
        ? `${months[0]}부터 ${months[months.length - 1]}까지`
        : '평가 기간 동안';
    lines.push(`${intro} ${overallParts.join('. ')}.`);
    lines.push('');
  }

  /* 1-2. 영역별 현재 수행 수준 - 8영역 각각 상세 진술 (CLINICAL 풀 활용) */
  lines.push('영역별 현재 수행 수준');
  lines.push('(아래 점수는 평가 기간 마지막 시점의 현재 수행 수준이며, 5점 척도 기준입니다.)');
  results.forEach(({ dom, avg, first, last, diff }) => {
    /* 묘사 매칭은 현재 시점(마지막 월) 점수 기준 — 표시 점수와 묘사가 어긋나지 않도록 */
    const refScore = last;
    const band = getScoreBand(refScore);
    const pool = poolDescriptions(domains)[dom.key]?.[band];
    const seed = (dom.key?.length || 0) + Math.floor(refScore * 10) + nameHash;
    let desc = pool && pool.length > 0 ? pickStable(pool, seed) : '';
    desc = toPresentTense(desc);

    /* 변화 추세 표시 (last + diff 종합 판단) */
    let trend = '';
    if (last >= 4.0 && diff >= 1.0) trend = ' · 안정화 도달';
    else if (last >= 4.0) trend = ' · 안정 유지';
    else if (diff >= 1.0 && last >= 2.8) trend = ' · 뚜렷한 향상';
    else if (diff >= 1.0) trend = ' · 향상 진행 중';
    else if (diff >= 0.5 && last >= 2.8) trend = ' · 점진적 향상';
    else if (diff >= 0.5) trend = ' · 향상 진행 중';
    else if (diff <= -1.0) trend = ' · 감소 추세';
    else if (diff <= -0.5) trend = ' · 다소 감소';
    else if (last <= 2.0) trend = ' · 지속 지원 필요';
    else trend = ' · 안정 유지';

    /* 영역별 상세 보정: 모순 방지 + 구체적 양상 추가
       ⚠ 점수가 high band(4점 이상)일 때는 CLINICAL_DESCRIPTIONS.high 표현 그대로 사용
       (강제 묘사는 mid·low일 때만 의미 있는 임상 표현) */
    if (dom.key === 'spontaneousGreeting' && diff >= 0.5) {
      /* 자발적 인사: 독립 수행이 핵심 → 촉구 없는 자발성 강조 (수행수준-상세 모순 제거) */
      desc = '촉구 없이도 자발적인 인사 행동이 나타나기 시작하며, 또래·교사와의 상호작용 상황에서 먼저 인사를 시도하는 빈도가 증가하고 있습니다';
    } else if (dom.key === 'taskCompletion' && diff >= 0.5) {
      /* 과제 완수: 수행수준(일과표 제시 시 완료)과 상세(정리까지) 매끄럽게 연결 */
      desc = '시각적 일과표가 제시되면 과제를 끝까지 완료하며, 활동 종료 후 정리 행동까지 스스로 이어가는 모습이 나타납니다';
    } else if (dom.key === 'participation' && band !== 'high') {
      /* 참여: 회기 간 변동의 이유 구체화 (high band일 땐 적용 안 함 — 변동 표현이 모순) */
      desc = '선호 활동이나 시각적 자극이 명확할 때는 10분 이상 착석과 집중이 유지되나, 구조화가 덜 되거나 비선호 과제 시에는 주의 집중 시간이 다소 짧아지는 회기 간 변동이 관찰됩니다';
    } else if (dom.key === 'selfRegulation' && band !== 'high') {
      desc = '원하는 강화를 즉시 얻지 못할 때 일시적인 좌절 행동을 보이나, 교사의 일관된 시각적 타이머 활용과 대기 촉구를 통해 스스로 감정을 가라앉히는 경험을 쌓아가고 있습니다';
    } else if (dom.key === 'waiting' && band !== 'high') {
      desc = '대기 상황에서 자리 이탈 경향을 보이나, 시각적 타이머와 단계적 대기 촉구를 활용하면 점차 짧은 시간 동안 자리를 유지합니다';
    }

    lines.push(`· ${dom.label} (현재 ${last.toFixed(1)}점${trend}): ${desc || '지속적인 관찰이 필요한 영역입니다'}`);
  });
  lines.push('');

  /* 2. 성장 영역 - 단락 글 + 행동 묘사
     ⚠ 모순 방지: '향상'했더라도 도달 수준(last)이 낮으면 긍정 마무리("안정적 진전")를
     붙이지 않는다. 도달 수준에 따라 마무리 문구를 다르게 생성. */
  if (major.length > 0) {
    const growthLines = [];
    major.slice(0, 3).forEach(({ dom, first, last, diff }) => {
      const band = getScoreBand(last);  // 향상 후 '실제 도달' 수준 기준
      const pool = poolDescriptions(domains)[dom.key]?.[band];
      const seed = (dom.key?.length || 0) + 3;
      let behaviorDesc = pool && pool.length > 0 ? pickStable(pool, seed) : '';
      behaviorDesc = toPresentTense(behaviorDesc)
        .replace(/관찰됩니다/g, '관찰되며')
        .replace(/확인됩니다/g, '확인되며')
        .replace(/수행합니다/g, '수행하며')
        .replace(/보입니다/g, '보이며')
        .replace(/가능합니다/g, '가능해지며')
        .replace(/참여합니다/g, '참여하며')
        .replace(/필요합니다/g, '필요한 상태이며')
        .replace(/요구됩니다/g, '요구되는 상태이며')
        .replace(/모방합니다/g, '모방하며')
        .replace(/완료합니다/g, '완료하며')
        /* 부정형·기타 종결어미도 연결형으로 (closing과 매끄럽게 이어지도록) */
        .replace(/관찰되지 않았습니다/g, '관찰되지 않으며')
        .replace(/확인되지 않았습니다/g, '확인되지 않으며')
        .replace(/되지 않았습니다/g, '되지 않으며')
        .replace(/되었습니다/g, '되었으며')
        .replace(/하였습니다/g, '하였으며')
        .replace(/단축되었습니다/g, '단축되었으며')
        .replace(/정착되었습니다/g, '정착되었으며')
        .replace(/(\S)습니다$/, '$1으며');

      /* 도달 수준에 맞는 마무리 문구 (모순 제거). closing 앞에 쉼표로 명확히 분리.
         "자리 잡아"라는 표현은 mid band 묘사의 "자리 이탈"과 충돌할 수 있어 "흐름"으로 표현 */
      let closing;
      if (last >= 3.5) {
        closing = '전반적으로 안정화 흐름이 이어지고 있습니다';
      } else if (last >= 2.5) {
        closing = '꾸준한 향상 흐름이 관찰되고 있습니다';
      } else {
        closing = '뚜렷한 상승 추세를 보이고 있어 지속적인 지원이 필요한 시점입니다';
      }
      growthLines.push(`${dom.label} 영역이 ${first.toFixed(1)}점에서 ${last.toFixed(1)}점으로 +${diff.toFixed(1)}점 향상되었습니다. 현재는 ${behaviorDesc} ${closing}`);
    });
    /* 다중 영역 묘사 시 "또한" 반복 단조로움 해결 — 회기별로 다른 connector */
    const growthConnectors = ['. 또한 ', '. 더불어 ', '. 함께 '];
    let joinedGrowth = growthLines[0] || '';
    for (let i = 1; i < growthLines.length; i++) {
      joinedGrowth += growthConnectors[(i - 1) % growthConnectors.length] + growthLines[i];
    }
    lines.push(`주요 성장 영역으로는, ${joinedGrowth}.`);
    lines.push('');
  }

  /* 2-2. 유의한 향상(+0.5~1.0) 및 소폭 향상(+0.2~0.5) 영역 - 초기→현재 행동 대비로 보강 */
  const gradual = [...meaningful, ...small];
  if (gradual.length > 0) {
    const names = gradual.map((c) => `${c.dom.label}(+${c.diff.toFixed(1)}점)`).join(', ');
    lines.push(`${names} 영역에서도 작은 폭이지만 향상이 확인되었습니다.`);

    /* 향상 폭이 큰 순으로 최대 2개 영역에 초기→현재 행동 변화 묘사 추가 */
    const sortedGradual = [...gradual].sort((a, b) => b.diff - a.diff);
    const contrast = [];
    sortedGradual.slice(0, 2).forEach((c) => {
      const dom = c.dom;
      const initBand = getScoreBand(c.first);
      const initPool = poolDescriptions(domains)[dom.key]?.[initBand];
      const seedI = (dom.key?.length || 0) + 2;
      let initDesc = initPool && initPool.length > 0 ? toPresentTense(pickStable(initPool, seedI)) : '';
      initDesc = initDesc
        .replace(/되었습니다$|됩니다$/, '되던')
        .replace(/하였습니다$|합니다$/, '하던')
        .replace(/보였습니다$|보입니다$/, '보이던')
        .replace(/관찰됩니다$|관찰되었습니다$/, '관찰되던')
        .replace(/확인됩니다$|확인되었습니다$/, '확인되던')
        .replace(/요구됩니다$|요구되었습니다$/, '요구되던')
        .replace(/필요합니다$|필요한 상태로 확인됩니다$/, '필요하던')
        .replace(/않습니다$|않았습니다$/, '않던')
        .replace(/없습니다$|없었습니다$/, '없던')
        .replace(/단계입니다$/, '단계이던')
        .replace(/시점입니다$/, '시점이던')
        .replace(/상태입니다$/, '상태이던')
        .replace(/시기입니다$/, '시기이던')
        .replace(/(\S+)입니다$/, '$1이던')
        .replace(/습니다$/, '던');
      const strengthPool = poolDomainStrengths(domains)[dom.key];
      const seedF = (dom.key?.length || 0) + 8;
      let strengthDesc = strengthPool && strengthPool.length > 0 ? pickStable(strengthPool, seedF) : '';
      /* DOMAIN_STRENGTHS는 보호자용 구어체("~했어요") → 보고서 본문 격식체로 변환 (포괄 패턴) */
      strengthDesc = strengthDesc
        .replace(/관찰됐어요$/, '관찰되었습니다')
        .replace(/(\S*)됐어요$/, '$1되었습니다')
        .replace(/(\S*)했어요$/, '$1하였습니다')
        .replace(/(\S*)웠어요$/, '$1웠습니다')
        /* 이미 과거형인 어간(이었/었/췄/줬 등)은 '었'을 덧붙이지 않고 '습니다'만 */
        .replace(/이었어요$/, '이었습니다')
        .replace(/였어요$/, '였습니다')
        .replace(/췄어요$/, '추었습니다')
        .replace(/맞췄어요$/, '맞추었습니다')
        .replace(/(\S*)았어요$/, '$1았습니다')
        .replace(/(\S*)졌어요$/, '$1졌습니다')
        .replace(/(\S*)겼어요$/, '$1겼습니다')
        .replace(/(\S*)왔어요$/, '$1왔습니다')
        .replace(/(\S*)었어요$/, '$1었습니다')
        .replace(/했습니다$/, '하였습니다')
        .replace(/해요$/, '합니다')
        .replace(/예요$/, '입니다')
        .replace(/이에요$/, '입니다')
        .replace(/줘요$/, '줍니다')
        .replace(/보여요$/, '보입니다')
        .replace(/나타나요$/, '나타납니다')
        .replace(/잡혔어요$/, '잡혔습니다')
        .replace(/(\S+)있어요$/, '$1있습니다')
        .replace(/(\S+)느려요$/, '$1느립니다')
        .replace(/(\S+)러요$/, '$1릅니다')
        .replace(/길어요$/, '깁니다')
        .replace(/늘어요$/, '늘어납니다')
        .replace(/늘었어요$/, '늘었습니다')
        .replace(/길어졌어요$/, '길어졌습니다')
        .replace(/많아져요$/, '많아집니다')
        .replace(/많아졌어요$/, '많아졌습니다')
        .replace(/이어가요$/, '이어갑니다')
        .replace(/이어가는 모습이 관찰돼요$/, '이어가는 모습이 관찰됩니다')
        .replace(/따라가요$/, '따라갑니다')
        .replace(/(\S+)가요$/, '$1갑니다')
        .replace(/(\S+)돼요$/, '$1됩니다')
        .replace(/지켜요$/, '지킵니다')
        .replace(/지내요$/, '지냅니다')
        .replace(/(\S)어요$/, '$1습니다');
      if (initDesc && strengthDesc) {
        const connector = /(관찰되던|확인되던|이던)$/.test(initDesc) ? ' 양상에서,' : ' 모습이 관찰되었으나,';
        contrast.push(`${dom.label} 영역은 초기에 ${initDesc}${connector} 현재는 ${strengthDesc}.`);
      } else if (strengthDesc) {
        contrast.push(`${dom.label} 영역은 현재 ${strengthDesc}.`);
      }
    });
    if (contrast.length > 0) {
      lines.push(contrast.join(' '));
    }
    lines.push('');
  }

  /* 3. 안정 영역 — 도입에서 이미 전 영역 케이스를 다뤘으면 중복 회피
     8개 모두 stable + 8개 모두 high/mid/low인 케이스는 도입에서 이미 "전반 영역에서..." 처리됨
     양극화(high+low 동시 등장)도 도입에서 두 카테고리 따로 안내되므로 stable 메시지는 모순/중복 */
  if (stable.length > 0 && major.length === 0 && meaningful.length === 0) {
    const allStable = stable.length === results.length;
    const allLowAndStable = allStable && lowDomains.length === results.length;
    const allMidAndStable = allStable && midDomains.length === results.length;
    const allHighAndStable = allStable && highDomains.length === results.length;
    /* 양극화: high와 low가 동시에 존재 → 도입에서 둘 다 안내됐으므로 "전 영역 안정" 메시지는 모순 */
    const isPolarized = highDomains.length > 0 && lowDomains.length > 0;
    /* 8개 모두 stable + 도입에서 한 카테고리로 6+개 처리한 경우 stable 분기는 중복 */
    const skipStable = allLowAndStable || allMidAndStable || allHighAndStable || isPolarized;
    if (!skipStable) {
      if (stable.length >= 6) {
        lines.push(`전 영역에서 안정적인 수행이 유지되고 있습니다.`);
      } else {
        const names = stable.map((s) => s.dom.label).join(', ');
        lines.push(`${names} 영역은 기간 내 안정적인 수행을 유지하고 있습니다.`);
      }
      lines.push('');
    }
  }

  /* 4. 다음 기간 중재 방향 - 강점(성장) 영역과 집중 중재 영역을 구분하여 차별화 */
  {
    /* 성장 영역: 향상 추세를 보인 영역 (Fading으로 독립성 강화) */
    const growthForPlan = [...major, ...meaningful];
    const growthKeys = new Set(growthForPlan.map((c) => c.dom.key));
    /* 집중 중재 영역: 낮은/중간 수준이면서 성장 영역에 포함되지 않은 영역 (구조화로 기반 다지기) */
    const focusForPlan = [...lowDomains, ...midDomains, ...declining]
      .filter((d, i, arr) => arr.findIndex((x) => x.dom.key === d.dom.key) === i)  // 중복 제거
      .filter((d) => !growthKeys.has(d.dom.key));

    let printedPlan = false;
    if (growthForPlan.length > 0) {
      /* 6개 이상이면 "전반 영역" 표현 */
      const planLabel = growthForPlan.length >= 6
        ? '전반 영역'
        : `${growthForPlan.slice(0, 4).map((c) => c.dom.label).join(', ')} 영역`;
      lines.push(`다음 기간에는 [성장 영역]인 ${planLabel}의 경우, 자발적인 수행이 나타나기 시작한 만큼 그동안 제공해 온 시각적·언어적 촉구를 조금씩 줄여 스스로 시작하고 이어가는 힘을 키우는 데 중점을 둡니다.`);
      printedPlan = true;
    }
    if (focusForPlan.length > 0) {
      const focusLabel = focusForPlan.length >= 6
        ? '전반 영역'
        : `${focusForPlan.slice(0, 5).map((d) => d.dom.label).join(', ')} 영역`;
      const lead = printedPlan ? '한편 ' : '다음 기간에는 ';
      lines.push(`${lead}[집중 중재 영역]인 ${focusLabel}은 단계적 촉구와 시각적 구조화(일과표, 타이머, 사회적 이야기)를 바탕으로 학교 적응의 기초를 다져갈 계획입니다. 특히 단체 지시를 따르고 혼자서 기다리는 능력을 핵심 목표로 두고 있습니다.`);
      printedPlan = true;
    }
    if (!printedPlan && highDomains.length > 0) {
      const names = highDomains.slice(0, 3).map((d) => d.dom.label).join(', ');
      lines.push(`다음 기간에는 ${names} 영역의 일반화에 중점을 두며, 또래 및 다양한 환경에서 자연스럽게 적용할 기회를 확대해갈 예정입니다.`);
    }
    lines.push('');
  }

  /* 5. 가정 연계 - 번호 매김 + 구체적 칭찬 멘트 강조 */
  const PRAISE = {
    preparation: '"스스로 가방을 제자리에 정리했네, 최고야!"',
    participation: '"끝까지 함께 활동해 줘서 정말 즐거웠어!"',
    followInstruction: '"한 번에 알아듣고 해줘서 고마워!"',
    ruleUnderstanding: '"약속을 스스로 지켜줘서 멋졌어!"',
    selfRegulation: '"기다리기 힘들었을 텐데 잘 가라앉혔구나, 대단해!"',
    waiting: '"차례를 끝까지 기다려 줘서 정말 멋졌어!"',
    spontaneousGreeting: '"스스로 먼저 인사해 줘서 반가웠어!"',
    taskCompletion: '"끝까지 다 하고 정리까지 했네, 훌륭해!"',
  };
  /* 가정 권고 대상: 현재(last) 시점 기준으로 지원이 필요한 영역 (avg 평균으로 보면
     "거쳐온 길"의 흐름이라 현재는 도달했어도 들어가는 어색함이 생김) */
  const lowByLast = results.filter((r) => r.last < 2.5);
  const midByLast = results.filter((r) => r.last >= 2.5 && r.last < 3.5);
  const focusForHome = [...lowByLast, ...midByLast, ...meaningful.filter((m) => m.last < 3.5)]
    .filter((d, i, arr) => arr.findIndex((x) => x.dom.key === d.dom.key) === i)
    .slice(0, 3);
  if (focusForHome.length > 0) {
    lines.push('가정에서 함께해주시면 좋은 부분');
    lines.push('센터에서의 변화가 가정에서도 일관되게 이어질 때 일반화가 촉진됩니다. 아래 내용을 일상에서 자연스럽게 적용해주시기를 권합니다.');
    /* 칭찬 멘트 연결 표현을 항목마다 다르게 → 반복되는 'AI 티' 완화 */
    const praiseLeads = [
      (p) => `잘 해냈을 때 ${p}처럼 구체적으로 짚어 칭찬해주세요.`,
      (p) => `그럴 때 ${p} 하고 바로 알아봐 주시면 큰 힘이 됩니다.`,
      (p) => `해낸 순간을 놓치지 말고 ${p}라고 말해주세요.`,
    ];
    focusForHome.forEach(({ dom }, idx) => {
      const homePool = poolHomeGuidance(domains)[dom.key];
      /* seed 기반 다양성 - 아동·영역마다 다른 표현 선택 (homePool[0]만 사용하던 단조로움 해결) */
      const tipSeed = (dom.key?.length || 0) + nameHash + idx * 3;
      let tip = homePool && homePool.length > 0 ? pickStable(homePool, tipSeed) : '관련 활동을 자연스럽게 함께 연습해주세요';
      if (PRAISE[dom.key]) {
        const tipBase = tip
          .replace(/해주세요$/, '해주시고')
          .replace(/주세요$/, '주시고')
          .replace(/늘려주세요$/, '늘려주시고')
          .replace(/만들어주세요$/, '만들어주시고')
          .replace(/지켜주세요$/, '지켜주시고')
          .replace(/연습해주세요$/, '연습해주시고')
          .replace(/권고드립니다$/, '권고드리며')
          .replace(/권합니다$/, '권하며')
          .replace(/도움됩니다$/, '도움되며')
          .replace(/필요합니다$/, '필요하며')
          .replace(/(\S+)드립니다$/, '$1드리며')
          .replace(/(\S+)됩니다$/, '$1되며');
        const lead = praiseLeads[idx % praiseLeads.length];
        lines.push(`${idx + 1}. [${dom.label}] ${tipBase}, ${lead(PRAISE[dom.key])}`);
      } else {
        lines.push(`${idx + 1}. [${dom.label}] ${tip}`);
      }
    });
    lines.push('');
  } else {
    lines.push('가정에서도 현재 익힌 활동을 자연스럽게 적용할 기회를 만들어주시고, 잘 해냈을 때 구체적으로 칭찬해주시면 좋겠습니다.');
    lines.push('');
  }

  /* 6. 치료사 종합 소견 (임상적 총평) */
  lines.push('치료사 종합 소견');
  const growthNames = [...major, ...meaningful].slice(0, 2).map((c) => c.dom.label);
  const growthPhrase = growthNames.length > 0
    ? `특히 ${growthNames.join(', ')} 영역에서 스스로 시도하려는 자발적인 모습이 늘어난 점은, 아동이 단순히 지시를 따르는 것을 넘어 '스스로 해보려는 힘'을 키워가고 있음을 보여주는 대견한 변화입니다.`
    : '낯선 환경과 새로운 규칙에 대한 부담을 조금씩 덜어내며 정해진 일과를 받아들이는 모습이 자리 잡아가고 있습니다.';
  lines.push(`지난 기간 동안 아동은 낯선 그룹과 새로운 규칙에 적응하느라 쉽지 않았을 텐데, 정해진 일과를 조금씩 받아들이며 잘 따라와 주었습니다. ${growthPhrase}`);
  lines.push('남은 기간의 목표는 이러한 변화를 실제 초등학교 교실 환경에서도 발휘할 수 있도록 일반화하는 데 있습니다. 교실에서는 교사의 단체 지시 수행, 독립적인 대기, 도움이 필요할 때 스스로 요청하기와 같은 기술이 요구되므로, 센터에서는 실제 교실 상황을 모사한 구조화된 연습과 점진적인 촉구 감소를 통해 독립성을 키워가겠습니다.');
  lines.push('지금까지의 변화를 발판 삼아 센터와 가정이 같은 방향에서 꾸준히 도와준다면, 새로운 환경에서도 무리 없이 적응해 나갈 수 있으리라 봅니다.');

  return replaceChildPronoun(lines.join('\n'), childName);
};

/* 종결보고서 - "주요 목표 및 중재 방향 요약" 자동 생성
   초기 평가 결과 + 설정 목표 + 중재 방향 3단락 구조 */
const buildFinalGoalsAndDirection = (initialScores, childName, totalSessions, info) => {
  const initVals = Object.values(initialScores).map((v) => Number(v)).filter((v) => !isNaN(v));
  if (initVals.length === 0) {
    return '※ 영역별 초기 점수를 먼저 입력해주세요 (영역별 변화 요약 표).';
  }
  const initAvg = initVals.reduce((a, b) => a + b, 0) / initVals.length;

  /* 초기 점수 기준 분류: 강점(3.5+) · 도전 영역(2.0 이하) */
  const initSorted = EVAL_DOMAINS
    .map((d) => ({ dom: d, init: Number(initialScores[d.key]) }))
    .filter((x) => !isNaN(x.init))
    .sort((a, b) => b.init - a.init);
  const initStrengths = initSorted.filter((x) => x.init >= 3.5);
  const initChallenges = initSorted.filter((x) => x.init <= 2).reverse();

  /* 중재 기간 라벨 (종결보고서와 동일 로직) */
  const getDurationLabelGoals = (start, end) => {
    if (!start || !end) return '학교 준비반 전 과정';
    try {
      const s = new Date(start);
      const e = new Date(end);
      if (isNaN(s.getTime()) || isNaN(e.getTime())) return '학교 준비반 전 과정';
      const days = Math.round((e - s) / (1000 * 60 * 60 * 24));
      if (days < 14) return '단기 평가 기간';
      if (days < 30) {
        const weeks = Math.round(days / 7);
        return `약 ${weeks}주간의 평가 기간`;
      }
      if (days < 365) {
        const months = Math.round(days / 30);
        const monthNames = ['', '한 달', '두 달', '세 달', '네 달', '다섯 달', '여섯 달', '일곱 달', '여덟 달', '아홉 달', '열 달', '열한 달', '열두 달'];
        return `약 ${monthNames[months] || months + '개월'}간의 평가 기간`;
      }
      return `약 ${Math.round(days / 30)}개월간의 평가 기간`;
    } catch (e) {
      return '학교 준비반 전 과정';
    }
  };
  const durationLabel = getDurationLabelGoals(info?.evalStart, info?.evalEnd);
  const sessionLabel = totalSessions > 0 ? ` 총 ${totalSessions}회기` : '';

  const lines = [];

  /* 1. 도입 + 초기 평가 결과 */
  lines.push(`아동은 ${durationLabel} 동안${sessionLabel} 검단ABA언어행동연구소 학교 준비반 프로그램에 참여하였습니다. 본 프로그램은 초등학교 진학을 앞두고 학교 환경에서 요구되는 핵심 행동을 8개 영역(준비·참여·지시 따르기·규칙 이해·자기조절·대기행동·자발적 인사·과제 완수)으로 구분하여 평가·중재하는 구조화된 그룹 프로그램입니다.`);

  /* 2. 초기 평가 결과 */
  let initEval = `중재 시작 시점의 영역별 평가에서 전반 평균 ${initAvg.toFixed(1)}점이 확인되었으며, `;
  if (initStrengths.length > 0 && initChallenges.length > 0) {
    const sNames = initStrengths.slice(0, 2).map((x) => x.dom.label).join(', ');
    const cNames = initChallenges.slice(0, 2).map((x) => x.dom.label).join(', ');
    initEval += `${sNames} 영역에서는 비교적 안정적인 수행이 관찰된 반면, ${cNames} 영역에서는 부분 또는 신체 촉구가 필요한 수준이었습니다.`;
  } else if (initStrengths.length > 0) {
    const sNames = initStrengths.slice(0, 2).map((x) => x.dom.label).join(', ');
    initEval += `${sNames} 영역에서는 비교적 안정적인 수행이 확인되었으며, 그 외 영역에서는 단계적인 지원과 일반화 점검이 권장되는 수준이었습니다.`;
  } else if (initChallenges.length > 0) {
    const cNames = initChallenges.slice(0, 3).map((x) => x.dom.label).join(', ');
    initEval += `특히 ${cNames} 영역에서 부분 또는 신체 촉구가 필요한 수준으로, 8개 영역 전반에서 단계적 지원이 권장되는 출발점이었습니다.`;
  } else {
    initEval += `8개 영역 전반에서 기초 수행은 자리 잡았으나 안정화와 일반화가 더 필요한 수준이었습니다.`;
  }
  lines.push(initEval);
  lines.push('');

  /* 3. 설정한 주요 목표 */
  lines.push('설정한 주요 목표');
  lines.push(`각 영역별로 학교 환경에서의 핵심 행동을 측정 가능한 형태로 설정하였으며, 다음 사항을 우선 목표로 두었습니다.`);
  if (initChallenges.length > 0) {
    initChallenges.slice(0, 3).forEach(({ dom }) => {
      lines.push(`· ${dom.label} 영역의 자발 수행 빈도 증가 및 촉구 의존도 단계적 감소`);
    });
    if (initStrengths.length > 0) {
      const sNames = initStrengths.slice(0, 2).map((x) => x.dom.label).join('·');
      lines.push(`· ${sNames} 영역의 일반화 (다양한 환경·구성원·시간대에서 일관된 수행)`);
    }
  } else {
    lines.push(`· 8개 영역 전반의 안정화 및 학교 환경 일반화`);
    lines.push(`· 또래 모델과 상호작용 빈도 증가`);
    lines.push(`· 자발 시도와 독립 수행 단계 진입`);
  }
  lines.push('');

  /* 4. 중재 방향 */
  lines.push('중재 방향');
  lines.push(`구조화된 그룹 환경에서 또래 모델과 함께 학교 일과(등원·자리 정리·수업·대기·인사·하원)를 반복 노출하였습니다. 단계적 촉구 감소, 자연 환경 강화로의 전환, 시각 단서(일과표·체크리스트·타이머) 활용을 통해 자발 행동 빈도를 점진적으로 늘려가는 방향으로 진행하였으며, 가정에서도 동일한 행동을 일관되게 적용하실 수 있도록 보호자 안내와 가정 연계 자료(주간 가이드·5분 활동)를 함께 제공하였습니다.`);

  return replaceChildPronoun(lines.join('\n'), childName);
};

/* 종결보고서 - 종합 평가 자동 생성 (ABA 임상 표현, 점수 기반) */
const buildFinalSummary = (changes, childName, totalSessions, initialScores, finalScores, stats, info, domains = EVAL_DOMAINS) => {
  /* changes: { domainKey: { initial, final, summary } }
     initialScores/finalScores: { domainKey: number } - 영역별 평균 점수
     stats: { totalAttempted, actualEvaluated, absent, partial, consult, reeval, planned, extended }
     info: { evalStart, evalEnd } - 중재 기간 라벨 동적 계산용 */
  /* 중재 기간 자연어 라벨 ('여섯 달' 같은 hardcoded 대신 실제 기간 기반) */
  const getDurationLabel = (s, e) => {
    if (!s || !e) return '지난 기간 동안';
    const start = new Date(s);
    const end = new Date(e);
    if (isNaN(start) || isNaN(end) || end <= start) return '지난 기간 동안';
    const days = Math.round((end - start) / (1000 * 60 * 60 * 24));
    if (days < 14) return '지난 기간 동안';
    if (days < 30) return `지난 ${Math.round(days / 7)}주 동안`;
    const months = Math.round(days / 30);
    const koMonths = ['', '한 달', '두 달', '세 달', '넉 달', '다섯 달', '여섯 달', '일곱 달', '여덟 달', '아홉 달', '열 달', '열한 달', '열두 달'];
    if (months <= 12) return `지난 ${koMonths[months]} 동안`;
    return `지난 ${months}개월 동안`;
  };
  const durationLabel = getDurationLabel(info?.evalStart, info?.evalEnd);
  const results = [];
  domains.forEach((dom) => {
    const i = initialScores?.[dom.key];
    const f = finalScores?.[dom.key];
    if (i == null || f == null) return;
    const diff = f - i;
    const phrase = changeToAbaPhrase(diff);
    results.push({ dom, initial: i, final: f, diff, phrase });
  });

  const lines = [];

  if (results.length === 0) {
    lines.push('비교 가능한 회기 기록이 부족하여 분석이 제한됩니다.');
    return replaceChildPronoun(lines.join('\n'), childName);
  }

  /* === 분류 - 그래프와 중복 없이 통찰 제공 ===
     모든 영역이 정확히 하나의 그룹에 속하도록 우선순위 기반으로 분류
     (이전: final>=2.5 이면서 diff<=-0.5 인 하락 영역이 어느 그룹에도 안 잡혀 누락되던 문제 해결) */
  const sortedByGrowth = [...results].sort((a, b) => b.diff - a.diff);

  const standoutGrowth = sortedByGrowth.filter((r) => r.diff >= 1.5);
  const steadyGrowth = sortedByGrowth.filter((r) => r.diff >= 0.5 && r.diff < 1.5);
  /* 하락 영역: 절대 수준과 무관하게 0.5점 이상 떨어진 영역 (별도 관찰 필요) */
  const declining = sortedByGrowth.filter((r) => r.diff <= -0.5);
  /* 지속 지원 필요: 최종 수준이 낮은 영역.
     ⚠ 이미 성장 영역(두드러진/꾸준한)으로 분류된 영역은 제외 → '향상'과 '지원 필요' 중복 등장 방지.
     단, 향상했더라도 종결 수준이 매우 낮은(<2.0) 영역은 지원이 실제로 필요하므로 포함 허용. */
  const growthKeys = new Set([...standoutGrowth, ...steadyGrowth].map((r) => r.dom.key));
  const needsHelp = sortedByGrowth.filter((r) =>
    r.final < 2.5 && r.diff > -0.5
    && (!growthKeys.has(r.dom.key) || r.final < 2.0)
  );
  /* 안정 유지: 위 어디에도 안 들어간 나머지 (큰 변동 없이 유지) */
  const classified = new Set([...standoutGrowth, ...steadyGrowth, ...declining, ...needsHelp]);
  const stable = sortedByGrowth.filter((r) => !classified.has(r));
  /* === 분류 결과 조합 검사 ===
     "5→5 정체" "4→4 정체"처럼 stable + mastered가 모두 전체 영역일 때
     "안정화 도달" 메시지가 3번(overall + stable + mastered) 중복되지 않도록 통합 처리 */
  const masteredDomains = results.filter((r) => r.final >= 4.0);
  const allStableAndMastered = stable.length === changes.length && masteredDomains.length === changes.length && declining.length === 0;

  /* 격식체 변환 헬퍼 - 비격식 어미를 격식체로 변환 */
  const toFormal = (text) => {
    if (!text) return text;
    return text
      .replace(/이에요\./g, '입니다.')
      .replace(/이에요$/g, '입니다')
      .replace(/예요\./g, '입니다.')
      .replace(/예요$/g, '입니다')
      .replace(/했어요\./g, '하였습니다.')
      .replace(/했어요$/g, '하였습니다')
      .replace(/됐어요\./g, '되었습니다.')
      .replace(/됐어요$/g, '되었습니다')
      .replace(/있어요\./g, '있습니다.')
      .replace(/있어요$/g, '있습니다')
      .replace(/없어요\./g, '없습니다.')
      .replace(/없어요$/g, '없습니다')
      .replace(/돼요\./g, '됩니다.')
      .replace(/돼요$/g, '됩니다')
      .replace(/(\S+)해요\./g, '$1합니다.')
      .replace(/(\S+)해요$/g, '$1합니다')
      .replace(/주세요\./g, '주시기 바랍니다.')
      .replace(/주세요$/g, '주시기 바랍니다')
      .replace(/좋아요\./g, '좋습니다.')
      .replace(/좋아요$/g, '좋습니다')
      /* 추가 동사 어미 */
      .replace(/이어갔어요/g, '이어갔습니다')
      .replace(/형성되었어요/g, '형성되었습니다')
      .replace(/도달했어요/g, '도달하였습니다')
      .replace(/관찰됐어요/g, '관찰되었습니다')
      .replace(/유지했어요/g, '유지하였습니다')
      .replace(/이뤘어요/g, '이루었습니다')
      .replace(/이루어졌어요/g, '이루어졌습니다')
      .replace(/이루어진다/g, '이루어집니다')
      .replace(/(\S+)되었어요/g, '$1되었습니다')
      .replace(/이었어요/g, '이었습니다')
      .replace(/맞췄어요/g, '맞추었습니다')
      .replace(/췄어요/g, '추었습니다')
      .replace(/(\S+)었어요/g, '$1었습니다')
      .replace(/(\S+)였어요/g, '$1였습니다')
      .replace(/(\S+)셨어요/g, '$1셨습니다')
      /* 일부 표현의 어미 정리 */
      .replace(/잘했어요/g, '잘 수행하였습니다')
      .replace(/보였어요/g, '보였습니다')
      .replace(/보여요/g, '보입니다')
      .replace(/나타나요/g, '나타납니다')
      .replace(/잡혔어요/g, '잡혔습니다')
      .replace(/길어졌어요/g, '길어졌습니다')
      .replace(/많아져요/g, '많아집니다')
      .replace(/많아졌어요/g, '많아졌습니다')
      .replace(/이어가요/g, '이어갑니다')
      .replace(/따라가요/g, '따라갑니다')
      .replace(/(\S+)가요\b/g, '$1갑니다')
      .replace(/지켜요/g, '지킵니다')
      .replace(/(\S+)혔어요/g, '$1혔습니다')
      .replace(/늘었어요/g, '늘었습니다')
      .replace(/할게요/g, '하겠습니다')
      .replace(/할거예요/g, '할 예정입니다')
      .replace(/예정이에요/g, '예정입니다')
      /* "~줘요" 패턴 (보여줘요, 도와줘요 등) */
      .replace(/보여줘요/g, '보입니다')
      .replace(/(\S+)줘요\b/g, '$1 줍니다')
      /* 포괄 구어체 어미 (위 개별 패턴에서 안 잡힌 것들) */
      .replace(/(\S*)웠어요/g, '$1웠습니다')
      .replace(/(\S*)았어요/g, '$1았습니다')
      .replace(/(\S*)했어요/g, '$1하였습니다')
      .replace(/(\S*)졌어요/g, '$1졌습니다')
      .replace(/(\S*)겼어요/g, '$1겼습니다')
      .replace(/(\S*)왔어요/g, '$1왔습니다')
      .replace(/(\S*)줬어요/g, '$1주었습니다')
      .replace(/어요\b/g, '습니다');
  };

  /* 1. 종결 평가 개요 - 격식 있는 도입 단락 */
  /* 전체 평균 성장폭 계산 (종합 관점 도입 문장용) */
  const avgInitial = results.reduce((a, r) => a + r.initial, 0) / results.length;
  const avgFinal = results.reduce((a, r) => a + r.final, 0) / results.length;
  const avgDiff = avgFinal - avgInitial;
  const growthCount = results.filter((r) => r.diff >= 0.5).length;

  {
    let leadSentence = `아동은 학교 준비반 전 과정에 참여하였으며, ${domains.length}개 평가 영역 전반의 평균 점수가 초기 ${avgInitial.toFixed(1)}점에서 종결 ${avgFinal.toFixed(1)}점으로 변화하였습니다`;
    if (avgDiff >= 0.5) {
      leadSentence += ` (평균 +${avgDiff.toFixed(1)}점 향상).`;
    } else if (avgDiff > -0.2) {
      leadSentence += ` (전반적으로 수행 수준이 유지됨).`;
    } else {
      leadSentence += `.`;
    }
    if (growthCount > 0) {
      if (growthCount === results.length) {
        leadSentence += ` 전체 ${results.length}개 영역 모두에서 유의한 향상이 확인되었습니다.`;
      } else {
        leadSentence += ` 전체 ${results.length}개 영역 중 ${growthCount}개 영역에서 유의한 향상이 확인되었습니다.`;
      }
    }
    lines.push(leadSentence);
    lines.push('');
  }

  const overallParts = [];
  if (standoutGrowth.length > 0) {
    const names = standoutGrowth.slice(0, 3).map((r) => r.dom.label).join(', ');
    overallParts.push(`${names} 영역에서 두드러진 성장이 관찰되었습니다`);
  }
  if (masteredDomains.length > 0 && standoutGrowth.length === 0 && !allStableAndMastered) {
    const names = masteredDomains.slice(0, 3).map((r) => r.dom.label).join(', ');
    overallParts.push(`${names} 영역에서 자발 수행이 안정화된 수준에 도달하였습니다`);
  }
  /* steadyGrowth는 아래 별도 상세 단락에서 다루므로 종합 요약에서는 생략 (중복 방지) */
  if (overallParts.length > 0) {
    lines.push(`프로그램 전 기간을 종합한 결과, ${overallParts.join('. ')}.`);
    lines.push('');
  }

  /* 2. 주요 성장 영역 - 단락 글로 (점수 명시 유지 — 격식 문서 특성) */
  if (standoutGrowth.length > 0) {
    const growthSentences = [];
    standoutGrowth.slice(0, 2).forEach(({ dom, initial, final, diff }) => {
      const strengthPool = poolDomainStrengths(domains)[dom.key];
      const seed = (dom.key?.length || 0) + Math.floor(final * 10);
      const strengthRaw = strengthPool && strengthPool.length > 0 ? pickStable(strengthPool, seed) : '';
      const strength = toFormal(strengthRaw);
      growthSentences.push(
        `${dom.label} 영역은 초기 ${initial.toFixed(1)}점에서 종결 ${final.toFixed(1)}점으로 ${diff.toFixed(1)}점 올라, ${strength || '자발적인 수행이 안정적으로 자리 잡았습니다'}.`
      );
    });
    lines.push(`주요 성장 영역을 살펴보면, ${growthSentences.join(' ')}`);
    lines.push('');
  }

  /* 3. 꾸준한 성장 영역 - 영역별 초기→종결 행동 변화 대비로 충실하게 서술 */
  if (steadyGrowth.length > 0) {
    const names = steadyGrowth.map((r) => r.dom.label).join(', ');
    lines.push(`${names} 영역에서 회기를 거듭하며 점진적인 향상이 관찰되었습니다.`);

    /* 영역별 초기 수준 → 종결 수준의 구체적 행동 대비 (최대 3개 영역)
       초기: 낮은 밴드의 임상 묘사(어떤 어려움이 있었는지)
       종결: 향상 강점 표현(DOMAIN_STRENGTHS) — '향상되어 현재는 긍정적' 흐름 유지 (모순 방지) */
    const contrastSentences = [];
    steadyGrowth.slice(0, 3).forEach(({ dom, initial, final, diff }, ci) => {
      const initBand = getScoreBand(initial);
      const initPool = poolDescriptions(domains)[dom.key]?.[initBand];
      const seedI = (dom.key?.length || 0) + 2;
      let initDesc = initPool && initPool.length > 0 ? toFormal(pickStable(initPool, seedI)) : '';
      /* 초기 묘사를 '~던' 관형형으로 다듬어 자연스럽게 연결 */
      initDesc = initDesc
        .replace(/되었습니다$|되었다$|됩니다$/, '되던')
        .replace(/하였습니다$|하였다$|합니다$/, '하던')
        .replace(/보였습니다$|보였다$|보입니다$/, '보이던')
        .replace(/관찰되었습니다$|관찰되었다$|관찰됩니다$/, '관찰되던')
        .replace(/확인되었습니다$|확인되었다$|확인됩니다$/, '확인되던')
        .replace(/요구되었습니다$|요구하였습니다$|요구됩니다$/, '요구되던')
        .replace(/필요하였습니다$|필요한 상태로 확인되었습니다$|필요합니다$/, '필요하던')
        .replace(/않았습니다$|않았다$|않습니다$/, '않던')
        .replace(/없었습니다$|없었다$|없습니다$/, '없던')
        .replace(/단계입니다$/, '단계이던')
        .replace(/시점입니다$/, '시점이던')
        .replace(/상태입니다$/, '상태이던')
        .replace(/시기입니다$/, '시기이던')
        .replace(/(\S+)입니다$/, '$1이던')
        .replace(/습니다$/, '던');

      const strengthPool = poolDomainStrengths(domains)[dom.key];
      const seedF = (dom.key?.length || 0) + 9;
      const strengthDesc = strengthPool && strengthPool.length > 0 ? toFormal(pickStable(strengthPool, seedF)) : '';

      if (initDesc && strengthDesc) {
        /* initDesc가 '~던' 관형형으로 끝나면 '모습이 관찰' 중복 → '양상에서'로 연결
           '관찰되던/확인되던/않던/없던/이던/필요하던/되던/하던' 등 모든 ~던 패턴 커버 */
        const connector = /던$/.test(initDesc) ? ' 양상에서,' : ' 모습이 관찰되었으나,';
        /* 시작 표현을 영역마다 다르게 → 단조로운 'OO 영역은 초기에' 반복 완화 */
        const opener = ci === 0 ? `${dom.label} 영역은 처음에는`
          : ci === 1 ? `${dom.label} 영역도 초반에는`
          : `${dom.label} 영역 역시 시작 무렵에는`;
        contrastSentences.push(
          `${opener} ${initDesc}${connector} 지금은 ${strengthDesc}.`
        );
      } else if (strengthDesc) {
        const opener = ci === 0 ? `${dom.label} 영역은` : ci === 1 ? `${dom.label} 영역도` : `${dom.label} 영역 역시`;
        contrastSentences.push(`${opener} 지금은 ${strengthDesc}.`);
      }
    });
    if (contrastSentences.length > 0) {
      lines.push(contrastSentences.join(' '));
    }
    lines.push('');
  }

  /* 4. 안정적으로 유지된 영역 */
  if (stable.length > 0) {
    if (allStableAndMastered) {
      /* 5→5 / 4→4 정체 케이스 — stable + mastered 통합 한 줄 (3중 중복 방지) */
      lines.push(`전 영역에서 프로그램 전 기간 동안 평균 4.0점 이상의 일관된 수행이 유지되었으며, 대부분의 상황에서 촉구 없이 자발적으로 수행하는 안정화 수준에 도달하였습니다.`);
    } else if (stable.length === changes.length) {
      /* 8개 영역 모두 안정 — 영역명 나열 대신 "전 영역" 표현 */
      lines.push(`전 영역에서 프로그램 전 기간 동안 일관된 수행이 유지되었습니다.`);
    } else {
      const names = stable.map((r) => r.dom.label).join(', ');
      lines.push(`${names} 영역은 프로그램 전 기간 동안 일관된 수행을 유지하였습니다.`);
    }
    lines.push('');
  }

  /* 4-1. 자발 수행이 안정화된 영역 (마스터) - 별도 강조 단락
     단, 주요 성장 단락에서 이미 언급된 영역과 중복되지 않도록 필터
     또한 allStableAndMastered 케이스는 이미 stable 분기에서 통합 표현됨 → skip */
  if (masteredDomains.length > 0 && !allStableAndMastered) {
    /* "두드러진 성장" 단락에서 이미 언급된 영역(slice 0,3)과 중복 회피
       — 도입의 "준비, 지시 따르기, 자기조절 영역에서 두드러진 성장"이 3개 표시되는 것과 일치해야 마스터 단락에 중복 안 됨 */
    const standoutKeys = new Set(standoutGrowth.slice(0, 3).map((r) => r.dom.key));
    const masteredToMention = masteredDomains.filter((r) => !standoutKeys.has(r.dom.key));
    if (masteredToMention.length > 0) {
      if (masteredToMention.length === changes.length) {
        lines.push(`전 영역에서 종결 시점 평균 4.0점 이상으로, 대부분의 상황에서 촉구 없이 자발적으로 수행하는 안정화 수준에 도달하였습니다.`);
      } else {
        const names = masteredToMention.map((r) => r.dom.label).join(', ');
        lines.push(`${names} 영역은 종결 시점 평균 4.0점 이상으로, 대부분의 상황에서 촉구 없이 자발적으로 수행하는 안정화 수준에 도달하였습니다.`);
      }
      lines.push('');
    }
  }

  /* 4-2. 변동·하락이 관찰된 영역 - 객관적 관찰 진술 (긍정/부정 단정 배제) */
  if (declining.length > 0) {
    if (declining.length === changes.length) {
      /* 8개 모두 같은 하락 — 영역명 나열 대신 평균 변화로 묶어서 표현 */
      const avgInitial = declining.reduce((a, b) => a + b.initial, 0) / declining.length;
      const avgFinal = declining.reduce((a, b) => a + b.final, 0) / declining.length;
      const avgDiff = avgFinal - avgInitial;
      lines.push(
        `전 영역에서 회기 후반부에 점수 변동이 관찰되었습니다 (평균 ${avgInitial.toFixed(1)}점 → ${avgFinal.toFixed(1)}점, ${avgDiff.toFixed(1)}점). ` +
        `평가 과제의 난이도가 올라가거나 환경, 그날의 컨디션 등 여러 요인이 겹쳐 나타날 수 있는 자연스러운 변화로 보이는데, 학교에 입학한 뒤에도 이 부분이 어떻게 자리 잡아가는지 함께 지켜봐 주시면 좋겠습니다.`
      );
    } else {
      const declSentences = declining.map(({ dom, initial, final, diff }) =>
        `${dom.label} 영역(초기 ${initial.toFixed(1)}점 → 종결 ${final.toFixed(1)}점, ${diff.toFixed(1)}점)`
      );
      lines.push(
        `${declSentences.join(', ')}에서는 회기 후반부에 점수 변동이 보였습니다. ` +
        `평가 과제의 난이도가 올라가거나 환경, 그날의 컨디션 등 여러 요인이 겹쳐 나타날 수 있는 자연스러운 변화로 보이는데, 학교에 입학한 뒤에도 이 부분이 어떻게 자리 잡아가는지 함께 지켜봐 주시면 좋겠습니다.`
      );
    }
    lines.push('');
  }

  /* 5. 지속 지원이 필요한 영역 - 다정한 구어체 */
  if (needsHelp.length > 0) {
    const helpSentences = [];
    /* 문장 시작을 영역마다 다르게 → 'OO 영역은' 반복 완화 */
    const openers = [
      (label, score) => `${label} 영역(현재 ${score}점)은 `,
      (label, score) => `${label} 영역의 경우 `,
      (label, score) => `${label}(${score}점)에서는 `,
      (label, score) => `이어서 ${label} 영역은 `,
    ];
    needsHelp.forEach(({ dom, final }, idx) => {
      const recPool = poolDomainRecommendations(domains)[dom.key];
      const seed = (dom.key?.length || 0) + 11;
      const recRaw = recPool && recPool.length > 0 ? pickStable(recPool, seed) : '';
      const rec = toFormal(recRaw) || '학교에서도 꾸준한 지원이 필요해 보입니다';
      const opener = openers[idx % openers.length](dom.label, final.toFixed(1));
      helpSentences.push(`${opener}${rec}.`);
    });
    lines.push(`아직 손이 조금 더 가는 영역들은 이렇게 도와가려 합니다. ${helpSentences.join(' ')}`);
    lines.push('');
  }

  /* 6. 학교 환경 일반화 - 권고 어미 반복 제거, 평서형 + 부드러운 도입 */
  const recommendationParts = [];

  if (masteredDomains.length > 0) {
    const names = masteredDomains.slice(0, 3).map((r) => r.dom.label).join(', ');
    recommendationParts.push(`${names} 영역에서 자리 잡은 자발적인 행동은 교실에서도 선생님의 칭찬을 받으며 이어질 수 있습니다`);
  }
  if (needsHelp.length > 0) {
    const names = needsHelp.map((r) => r.dom.label).join(', ');
    recommendationParts.push(`${names} 영역에는 일과표나 사회적 이야기 같은 시각 자료와 단계적인 안내가 교실에서도 큰 힘이 됩니다`);
  }
  if (declining.length > 0) {
    if (declining.length === changes.length) {
      recommendationParts.push(`전 영역의 입학 후 변화를 가정과 학교가 함께 살펴봐 주시면 됩니다`);
    } else {
      const names = declining.map((r) => r.dom.label).join(', ');
      recommendationParts.push(`${names} 영역은 입학 후 변화를 가정과 학교가 함께 살펴봐 주시면 됩니다`);
    }
  }
  recommendationParts.push(`입학 초기 한두 달은 가정과 학교가 자주 소통하며 새 환경 적응을 함께 지켜보는 시기로 삼으시길 권합니다`);
  recommendationParts.push(`요청 카드나 감각 도구처럼 아동이 익힌 자기 조절 전략은 집과 학교에서 똑같이 쓰일 때 가장 효과가 큽니다`);

  lines.push(`학교생활로 넘어가실 때 몇 가지만 마음에 담아두셔도 좋겠습니다. ${recommendationParts.join('. ')}.`);
  lines.push('');

  /* 7. 가정 연계 - 지원 필요 영역 중심으로 가정에서 함께할 구체적 활동 (최대 3영역)
     CLINICAL_HOME_GUIDANCE 풀은 전부 "권고드립니다" 어미로 끝나므로 idx별 어미 다양화 적용 */
  const homeFocus = [...needsHelp, ...steadyGrowth].slice(0, 3);
  const homeEndingTransforms = [
    (s) => s, /* 1번: 그대로 "권고드립니다" */
    (s) => s.replace(/권고드립니다\.$/, '권합니다.'), /* 2번: "권합니다" */
    (s) => s.replace(/권고드립니다\.$/, '추천드립니다.'), /* 3번: "추천드립니다" */
  ];
  const homeLines = [];
  homeFocus.forEach(({ dom }, idx) => {
    const homePool = poolHomeGuidance(domains)[dom.key];
    if (homePool && homePool.length > 0) {
      const seed = (dom.key?.length || 0) + 5;
      let sentence = `${dom.label} 영역은 ${toFormal(pickStable(homePool, seed))}.`;
      const transform = homeEndingTransforms[idx % homeEndingTransforms.length];
      sentence = transform(sentence);
      homeLines.push(sentence);
    }
  });
  if (homeLines.length > 0) {
    lines.push(`가정에서도 이런 부분을 함께해 주시면 큰 도움이 됩니다. ${homeLines.join(' ')}`);
    lines.push('');
  }

  /* 8. 격려 마무리 - 다정한 구어체 */
  lines.push(`${durationLabel} 아동은 정말 많이 자랐습니다. 이 변화가 학교에서도 이어지려면 결국 곁에 있는 어른들이 같은 방향을 봐주는 것이 가장 큰 힘이 됩니다. 그동안 믿고 맡겨주셔서 감사했고, 새 출발을 앞둔 아동을 저희도 끝까지 응원하겠습니다.`);

  return replaceChildPronoun(lines.join('\n'), childName);
};


/* ────────────────────────────────────────────────
   5-2. 학교 전이(Transition) 평가 — 영역별 학교 환경 시나리오 풀
   ──────────────────────────────────────────────── */
